1	/**
2	 * @file
3	 * @brief BLIF Netlist Loader
4	 *
5	 * This loader handles loading a post-technology mapping fully flattened (i.e not
6	 * hierarchical) netlist in Berkely Logic Interchange Format (BLIF) file, and
7	 * builds a netlist data structure (AtomNetlist) from it.
8	 *
9	 * BLIF text parsing is handled by the blifparse library, while this file is responsible
10	 * for creating the netlist data structure.
11	 *
12	 * The main object of interest is the BlifAllocCallback struct, which implements the
13	 * blifparse callback interface.  The callback methods are then called when basic blif
14	 * primitives are encountered by the parser.  The callback methods then create the associated
15	 * netlist data structures.
16	 */
17	#include <cstdio>
18	#include <cstring>
19	#include <ctime>
20	#include <sstream>
21	#include <cctype> //std::isdigit
22	#include <regex>  //std::regex
23	#include <optional>
24	
25	#include "blifparse.hpp"
26	#include "atom_netlist.h"
27	
28	#include "logic_types.h"
29	#include "vtr_assert.h"
30	#include "vtr_util.h"
31	#include "vtr_log.h"
32	#include "vtr_logic.h"
33	#include "vtr_digest.h"
34	
35	#include "vpr_error.h"
36	#include "read_blif.h"
37	#include "hash.h"
38	
39	vtr::LogicValue to_vtr_logic_value(blifparse::LogicValue);
40	
41	struct BlifAllocCallback : public blifparse::Callback {
42	  public:
43	    BlifAllocCallback(e_circuit_format blif_format, AtomNetlist& main_netlist, const std::string netlist_id, const LogicalModels& models)
44	        : main_netlist_(main_netlist)
45	        , netlist_id_(netlist_id)
46	        , models_(models)
47	        , blif_format_(blif_format) {
48	        VTR_ASSERT(blif_format_ == e_circuit_format::BLIF
49	                   || blif_format_ == e_circuit_format::EBLIF);
50	    }
51	
52	    static constexpr const char* OUTPAD_NAME_PREFIX = "out:";
53	
54	  public: //Callback interface
55	    void start_parse() override {}
56	
57	    void finish_parse() override {
58	        //When parsing is finished we *move* the main netlist
59	        //into the user object. This ensures we never have two copies
60	        //(consuming twice the memory).
61	        size_t main_netlist_idx = determine_main_netlist_index();
62	        main_netlist_ = std::move(blif_models_[main_netlist_idx]);
63	    }
64	
65	    void begin_model(std::string model_name) override {
66	        //Create a new model, and set it's name
67	
68	        blif_models_.emplace_back(model_name, netlist_id_);
69	        blif_models_black_box_.emplace_back(false);
70	        ended_ = false;
71	        set_curr_block(AtomBlockId::INVALID()); //This statement doesn't define a block, so mark invalid
72	    }
73	
74	    void inputs(std::vector<std::string> input_names) override {
75	        LogicalModelId blk_model_id = LogicalModels::MODEL_INPUT_ID;
76	        const t_model& blk_model = models_.get_model(blk_model_id);
77	
78	        VTR_ASSERT_MSG(!blk_model.inputs, "Inpad model has an input port");
79	        VTR_ASSERT_MSG(blk_model.outputs, "Inpad model has no output port");
80	        VTR_ASSERT_MSG(blk_model.outputs->size == 1, "Inpad model has non-single-bit output port");
81	        VTR_ASSERT_MSG(!blk_model.outputs->next, "Inpad model has multiple output ports");
82	
83	        for (const auto& input : input_names) {
84	            AtomBlockId blk_id = curr_model().create_block(input, blk_model_id);
85	            AtomPortId port_id = curr_model().create_port(blk_id, blk_model.outputs);
86	            AtomNetId net_id = curr_model().create_net(input);
87	            curr_model().create_pin(port_id, 0, net_id, PinType::DRIVER);
88	        }
89	        set_curr_block(AtomBlockId::INVALID()); //This statement doesn't define a block, so mark invalid
90	    }
91	
92	    void outputs(std::vector<std::string> output_names) override {
93	        LogicalModelId blk_model_id = LogicalModels::MODEL_OUTPUT_ID;
94	        const t_model& blk_model = models_.get_model(blk_model_id);
95	
96	        VTR_ASSERT_MSG(!blk_model.outputs, "Outpad model has an output port");
97	        VTR_ASSERT_MSG(blk_model.inputs, "Outpad model has no input port");
98	        VTR_ASSERT_MSG(blk_model.inputs->size == 1, "Outpad model has non-single-bit input port");
99	        VTR_ASSERT_MSG(!blk_model.inputs->next, "Outpad model has multiple input ports");
100	
101	        for (const auto& output : output_names) {
102	            //Since we name blocks based on their drivers we need to uniquify outpad names,
103	            //which we do with a prefix
104	            AtomBlockId blk_id = curr_model().create_block(OUTPAD_NAME_PREFIX + output, blk_model_id);
105	            AtomPortId port_id = curr_model().create_port(blk_id, blk_model.inputs);
106	            AtomNetId net_id = curr_model().create_net(output);
107	            curr_model().create_pin(port_id, 0, net_id, PinType::SINK);
108	        }
109	        set_curr_block(AtomBlockId::INVALID()); //This statement doesn't define a block, so mark invalid
110	    }
111	
112	    void names(std::vector<std::string> nets, std::vector<std::vector<blifparse::LogicValue>> so_cover) override {
113	        LogicalModelId blk_model_id = LogicalModels::MODEL_NAMES_ID;
114	        const t_model& blk_model = models_.get_model(blk_model_id);
115	
116	        VTR_ASSERT_MSG(nets.size() > 0, "BLIF .names has no connections");
117	
118	        VTR_ASSERT_MSG(blk_model.inputs, ".names model has no input port");
119	        VTR_ASSERT_MSG(!blk_model.inputs->next, ".names model has multiple input ports");
120	        if (static_cast<int>(nets.size()) - 1 > blk_model.inputs->size) {
121	            vpr_throw(VPR_ERROR_BLIF_F, filename_.c_str(), lineno_, "BLIF .names input size (%zu) greater than .names model input size (%d)",
122	                      nets.size() - 1, blk_model.inputs->size);
123	        }
124	
125	        VTR_ASSERT_MSG(blk_model.outputs, ".names has no output port");
126	        VTR_ASSERT_MSG(!blk_model.outputs->next, ".names model has multiple output ports");
127	        VTR_ASSERT_MSG(blk_model.outputs->size == 1, ".names model has non-single-bit output");
128	
129	        //Convert the single-output cover to a netlist truth table
130	        AtomNetlist::TruthTable truth_table;
131	        for (const auto& row : so_cover) {
132	            truth_table.emplace_back();
133	            for (auto val : row) {
134	                truth_table[truth_table.size() - 1].push_back(to_vtr_logic_value(val));
135	            }
136	        }
137	
138	        AtomBlockId blk_id = curr_model().create_block(nets[nets.size() - 1], blk_model_id, truth_table);
139	        set_curr_block(blk_id);
140	
141	        //Create inputs
142	        AtomPortId input_port_id = curr_model().create_port(blk_id, blk_model.inputs);
143	        for (size_t i = 0; i < nets.size() - 1; ++i) {
144	            AtomNetId net_id = curr_model().create_net(nets[i]);
145	
146	            curr_model().create_pin(input_port_id, i, net_id, PinType::SINK);
147	        }
148	
149	        //Figure out if the output is a constant generator
150	        bool output_is_const = false;
151	        if (truth_table.empty()
152	            || (truth_table.size() == 1 && truth_table[0].size() == 1 && truth_table[0][0] == vtr::LogicValue::FALSE)) {
153	            //An empty truth table in BLIF corresponds to a constant-zero
154	            //  e.g.
155	            //
156	            //  #gnd is a constant 0 generator
157	            //  .names gnd
158	            //
159	            //An single entry truth table with value '0' also corresponds to a constant-zero
160	            //  e.g.
161	            //
162	            //  #gnd2 is a constant 0 generator
163	            //  .names gnd2
164	            //  0
165	            //
166	            output_is_const = true;
167	            VTR_LOG("Found constant-zero generator '%s'\n", nets[nets.size() - 1].c_str());
168	        } else if (truth_table.size() == 1 && truth_table[0].size() == 1 && truth_table[0][0] == vtr::LogicValue::TRUE) {
169	            //A single-entry truth table with value '1' in BLIF corresponds to a constant-one
170	            //  e.g.
171	            //
172	            //  #vcc is a constant 1 generator
173	            //  .names vcc
174	            //  1
175	            //
176	            output_is_const = true;
177	            VTR_LOG("Found constant-one generator '%s'\n", nets[nets.size() - 1].c_str());
178	        }
179	
180	        //Create output
181	        AtomNetId net_id = curr_model().create_net(nets[nets.size() - 1]);
182	        AtomPortId output_port_id = curr_model().create_port(blk_id, blk_model.outputs);
183	        curr_model().create_pin(output_port_id, 0, net_id, PinType::DRIVER, output_is_const);
184	    }
185	
186	    void latch(std::string input, std::string output, blifparse::LatchType type, std::string control, blifparse::LogicValue init) override {
187	        if (type == blifparse::LatchType::UNSPECIFIED) {
188	            VTR_LOGF_WARN(filename_.c_str(), lineno_, "Treating latch '%s' of unspecified type as rising edge triggered\n", output.c_str());
189	        } else if (type != blifparse::LatchType::RISING_EDGE) {
190	            vpr_throw(VPR_ERROR_BLIF_F, filename_.c_str(), lineno_, "Only rising edge latches supported\n");
191	        }
192	
193	        if (control.empty()) {
194	            vpr_throw(VPR_ERROR_BLIF_F, filename_.c_str(), lineno_, "Latch must have a clock\n");
195	        }
196	
197	        LogicalModelId blk_model_id = LogicalModels::MODEL_LATCH_ID;
198	        const t_model& blk_model = models_.get_model(blk_model_id);
199	
200	        VTR_ASSERT_MSG(blk_model.inputs, "Has one input port");
201	        VTR_ASSERT_MSG(blk_model.inputs->next, "Has two input port");
202	        VTR_ASSERT_MSG(!blk_model.inputs->next->next, "Has no more than two input port");
203	        VTR_ASSERT_MSG(blk_model.outputs, "Has one output port");
204	        VTR_ASSERT_MSG(!blk_model.outputs->next, "Has no more than one input port");
205	
206	        const t_model_ports* d_model_port = blk_model.inputs;
207	        const t_model_ports* clk_model_port = blk_model.inputs->next;
208	        const t_model_ports* q_model_port = blk_model.outputs;
209	
210	        VTR_ASSERT(d_model_port->name == std::string("D"));
211	        VTR_ASSERT(clk_model_port->name == std::string("clk"));
212	        VTR_ASSERT(q_model_port->name == std::string("Q"));
213	        VTR_ASSERT(d_model_port->size == 1);
214	        VTR_ASSERT(clk_model_port->size == 1);
215	        VTR_ASSERT(q_model_port->size == 1);
216	        VTR_ASSERT(clk_model_port->is_clock);
217	
218	        //We set the initial value as a single entry in the 'truth_table' field
219	        AtomNetlist::TruthTable truth_table(1);
220	        truth_table[0].push_back(to_vtr_logic_value(init));
221	
222	        AtomBlockId blk_id = curr_model().create_block(output, blk_model_id, truth_table);
223	        set_curr_block(blk_id);
224	
225	        //The input
226	        AtomPortId d_port_id = curr_model().create_port(blk_id, d_model_port);
227	        AtomNetId d_net_id = curr_model().create_net(input);
228	        curr_model().create_pin(d_port_id, 0, d_net_id, PinType::SINK);
229	
230	        //The output
231	        AtomPortId q_port_id = curr_model().create_port(blk_id, q_model_port);
232	        AtomNetId q_net_id = curr_model().create_net(output);
233	        curr_model().create_pin(q_port_id, 0, q_net_id, PinType::DRIVER);
234	
235	        //The clock
236	        AtomPortId clk_port_id = curr_model().create_port(blk_id, clk_model_port);
237	        AtomNetId clk_net_id = curr_model().create_net(control);
238	        curr_model().create_pin(clk_port_id, 0, clk_net_id, PinType::SINK);
239	    }
240	
241	    void subckt(std::string subckt_model, std::vector<std::string> ports, std::vector<std::string> nets) override {
242	        VTR_ASSERT(ports.size() == nets.size());
243	
244	        LogicalModelId blk_model_id = models_.get_model_by_name(subckt_model);
245	        if (!blk_model_id.is_valid()) {
246	            vpr_throw(VPR_ERROR_BLIF_F, filename_.c_str(), lineno_,
247	                      "Subckt instantiates model '%s', but no such model exists in the architecture file.",
248	                      subckt_model.c_str());
249	        }
250	        const t_model& blk_model = models_.get_model(blk_model_id);
251	
252	        //We name the subckt based on the net its first output pin drives
253	        std::string subckt_name;
254	        for (size_t i = 0; i < ports.size(); ++i) {
255	            const t_model_ports* model_port = find_model_port(blk_model, ports[i]);
256	            VTR_ASSERT(model_port);
257	
258	            if (model_port->dir == OUT_PORT) {
259	                subckt_name = nets[i];
260	                break;
261	            }
262	        }
263	
264	        if (subckt_name.empty()) {
265	            //We need to name the block uniquely ourselves since there is no connected output
266	            subckt_name = unique_subckt_name();
267	
268	            //Since this is unusual, warn the user
269	            VTR_LOGF_WARN(filename_.c_str(), lineno_,
270	                          "Subckt of type '%s' at %s:%d has no output pins, and has been named '%s'\n",
271	                          blk_model.name.c_str(), filename_.c_str(), lineno_, subckt_name.c_str());
272	        }
273	
274	        //The name for every block should be unique, check that there is no name conflict
275	        if (AtomBlockId blk_id = curr_model().find_block(subckt_name)) {
276	            LogicalModelId conflicting_model = curr_model().block_model(blk_id);
277	            vpr_throw(VPR_ERROR_BLIF_F, filename_.c_str(), lineno_,
278	                      "Duplicate blocks named '%s' found in netlist."
279	                      " Existing block of type '%s' conflicts with subckt of type '%s'.",
280	                      subckt_name.c_str(), models_.get_model(conflicting_model).name.c_str(), subckt_model.c_str());
281	        }
282	
283	        //Create the block
284	        AtomBlockId blk_id = curr_model().create_block(subckt_name, blk_model_id);
285	        set_curr_block(blk_id);
286	
287	        for (size_t i = 0; i < ports.size(); ++i) {
288	            //Check for consistency between model and ports
289	            const t_model_ports* model_port = find_model_port(blk_model, ports[i]);
290	            VTR_ASSERT(model_port);
291	
292	            //Determine the pin type
293	            PinType pin_type = PinType::SINK;
294	            if (model_port->dir == OUT_PORT) {
295	                pin_type = PinType::DRIVER;
296	            } else {
297	                VTR_ASSERT_MSG(model_port->dir == IN_PORT, "Unexpected port type");
298	            }
299	
300	            //Make the port
301	            std::string port_base;
302	            size_t port_bit;
303	            std::tie(port_base, port_bit) = split_index(ports[i]);
304	
305	            AtomPortId port_id = curr_model().create_port(blk_id, find_model_port(blk_model, port_base));
306	
307	            //Make the net
308	            AtomNetId net_id = curr_model().create_net(nets[i]);
309	
310	            //Make the pin
311	            curr_model().create_pin(port_id, port_bit, net_id, pin_type);
312	        }
313	    }
314	
315	    void blackbox() override {
316	        LogicalModelId arch_model_id = models_.get_model_by_name(curr_model().netlist_name());
317	        if (!arch_model_id.is_valid()) {
318	            vpr_throw(VPR_ERROR_BLIF_F, filename_.c_str(), lineno_, "Blackbox BLIF model '%s' has no equivalent architecture model.",
319	                      curr_model().netlist_name().c_str());
320	        }
321	
322	        //We treat black-boxes as netlists during parsing so they should contain
323	        //only inpads/outpads
324	        for (const auto& blk_id : curr_model().blocks()) {
325	            auto blk_type = curr_model().block_type(blk_id);
326	            if (!(blk_type == AtomBlockType::INPAD || blk_type == AtomBlockType::OUTPAD)) {
327	                vpr_throw(VPR_ERROR_BLIF_F, filename_.c_str(), lineno_, "Unexpected primitives in blackbox model");
328	            }
329	        }
330	        set_curr_model_blackbox(true);
331	        set_curr_block(AtomBlockId::INVALID()); //This statement doesn't define a block, so mark invalid
332	    }
333	
334	    void end_model() override {
335	        if (ended_) {
336	            vpr_throw(VPR_ERROR_BLIF_F, filename_.c_str(), lineno_, "Unexpected .end");
337	        }
338	
339	        merge_conn_nets();
340	
341	        //Mark as ended
342	        ended_ = true;
343	
344	        set_curr_block(AtomBlockId::INVALID()); //This statement doesn't define a block, so mark invalid
345	    }
346	
347	    //BLIF Extensions
348	    void conn(std::string src, std::string dst) override {
349	        if (blif_format_ != e_circuit_format::EBLIF) {
350	            parse_error(lineno_, ".conn", "Supported only in extended BLIF format");
351	        }
352	
353	        //We allow the .conn to create the nets if they don't exist,
354	        //however typically they will have already been defined.
355	        AtomNetId driver_net = curr_model().create_net(src);
356	        AtomNetId sink_net = curr_model().create_net(dst);
357	
358	        //We eventually need to merge the driver and sink nets,
359	        //however we must defer that until all the net drivers
360	        //and sinks have been created (otherwise they may not
361	        //be properly merged depending on where the .conn is
362	        //declared).
363	        //
364	        //As a result we record the nets to merge and do the actual merging at
365	        //the end of the .model
366	        curr_nets_to_merge_.emplace_back(driver_net, sink_net);
367	
368	        set_curr_block(AtomBlockId::INVALID());
369	    }
370	
371	    void cname(std::string cell_name) override {
372	        if (blif_format_ != e_circuit_format::EBLIF) {
373	            parse_error(lineno_, ".cname", "Supported only in extended BLIF format");
374	        }
375	
376	        //Re-name the block
377	        curr_model().set_block_name(curr_block(), cell_name);
378	    }
379	
380	    void attr(std::string name, std::string value) override {
381	        if (blif_format_ != e_circuit_format::EBLIF) {
382	            parse_error(lineno_, ".attr", "Supported only in extended BLIF format");
383	        }
384	
385	        curr_model().set_block_attr(curr_block(), name, value);
386	    }
387	
388	    void param(std::string name, std::string value) override {
389	        if (blif_format_ != e_circuit_format::EBLIF) {
390	            parse_error(lineno_, ".param", "Supported only in extended BLIF format");
391	        }
392	
393	        // Validate the parameter value
394	        bool is_valid = is_string_param(value) || is_binary_param(value) || is_real_param(value);
395	
396	        if (!is_valid) {
397	            parse_error(lineno_, ".param", "Incorrect parameter value specification");
398	        }
399	
400	        curr_model().set_block_param(curr_block(), name, value);
401	    }
402	
403	    //Utilities
404	    void filename(std::string fname) override { filename_ = fname; }
405	
406	    void lineno(int line_num) override { lineno_ = line_num; }
407	
408	    void parse_error(const int curr_lineno, const std::string& near_text, const std::string& msg) override {
409	        vpr_throw(VPR_ERROR_BLIF_F, filename_.c_str(), curr_lineno,
410	                  "Error in blif file near '%s': %s\n", near_text.c_str(), msg.c_str());
411	    }
412	
413	  public:
414	    //Retrieve the netlist
415	    size_t determine_main_netlist_index() {
416	        //Look through all the models loaded, to find the one which is non-blackbox (i.e. has real blocks
417	        //and is not a blackbox).  To check for errors we look at all models, even if we've already
418	        //found a non-blackbox model.
419	
420	        std::optional<size_t> top_model_idx; //Not valid yet
421	
422	        for (size_t i = 0; i < blif_models_.size(); ++i) {
423	            if (!blif_models_black_box_[i]) {
424	                //A non-blackbox model
425	                if (!top_model_idx.has_value()) {
426	                    // Top model is first non-blackbox model found
427	                    top_model_idx = i;
428	                } else {
429	                    //We already have a top model
430	                    vpr_throw(VPR_ERROR_BLIF_F, filename_.c_str(), lineno_,
431	                              "Found multiple models with primitives. "
432	                              "Only one model can contain primitives, the others must be blackboxes.");
433	                }
434	            } else {
435	                //Verify blackbox models match the architecture
436	                verify_blackbox_model(blif_models_[i]);
437	            }
438	        }
439	
440	        if (!top_model_idx.has_value()) {
441	            vpr_throw(VPR_ERROR_BLIF_F, filename_.c_str(), lineno_,
442	                      "No non-blackbox models found. The main model must not be a blackbox.");
443	        }
444	
445	        //Return the main model
446	        return top_model_idx.value();
447	    }
448	
449	  private:
450	    const t_model_ports* find_model_port(const t_model& blk_model, const std::string& port_name) {
451	        //We need to handle both single, and multi-bit port names
452	        //
453	        //By convention multi-bit port names have the bit index stored in square brackets
454	        //at the end of the name. For example:
455	        //
456	        //   my_signal_name[2]
457	        //
458	        //indicates the 2nd bit of the port 'my_signal_name'.
459	        std::string trimmed_port_name;
460	        int bit_index;
461	
462	        //Extract the index bit
463	        std::tie(trimmed_port_name, bit_index) = split_index(port_name);
464	
465	        //We now have the valid bit index and port_name is the name excluding the index info
466	        VTR_ASSERT(bit_index >= 0);
467	
468	        //We now look through all the ports on the model looking for the matching port
469	        for (const t_model_ports* ports : {blk_model.inputs, blk_model.outputs}) {
470	            const t_model_ports* curr_port = ports;
471	            while (curr_port) {
472	                if (trimmed_port_name == curr_port->name) {
473	                    //Found a matching port, we need to verify the index
474	                    if (bit_index < curr_port->size) {
475	                        //Valid port index
476	                        return curr_port;
477	                    } else {
478	                        //Out of range
479	                        vpr_throw(VPR_ERROR_BLIF_F, filename_.c_str(), lineno_,
480	                                  "Port '%s' on architecture model '%s' exceeds port width (%d bits)\n",
481	                                  port_name.c_str(), blk_model.name.c_str(), curr_port->size);
482	                    }
483	                }
484	                curr_port = curr_port->next;
485	            }
486	        }
487	
488	        //No match
489	        vpr_throw(VPR_ERROR_BLIF_F, filename_.c_str(), lineno_,
490	                  "Found no matching port '%s' on architecture model '%s'\n",
491	                  port_name.c_str(), blk_model.name.c_str());
492	        return nullptr;
493	    }
494	
495	    /** @brief Splits the index off a signal name and returns the base signal name
496	     *         (excluding the index) and the index as an integer. For example
497	     *
498	     * "my_signal_name[2]"   -> "my_signal_name", 2
499	     */
500	    std::pair<std::string, int> split_index(const std::string& signal_name) {
501	        int bit_index = 0;
502	
503	        std::string trimmed_signal_name = signal_name;
504	
505	        auto iter = --signal_name.end(); //Initialized to the last char
506	        if (*iter == ']') {
507	            //The name may end in an index
508	            //
509	            //To verify, we iterate back through the string until we find
510	            //an open square brackets, or non digit character
511	            --iter; //Advance past ']'
512	            while (iter != signal_name.begin() && std::isdigit(*iter))
513	                --iter;
514	
515	            //We are at the first non-digit character from the end (or the beginning of the string)
516	            if (*iter == '[') {
517	                //We have a valid index in the open range (iter, --signal_name.end())
518	                std::string index_str(iter + 1, --signal_name.end());
519	
520	                //Convert to an integer
521	                std::stringstream ss(index_str);
522	                ss >> bit_index;
523	                VTR_ASSERT_MSG(!ss.fail() && ss.eof(), "Failed to extract signal index");
524	
525	                //Trim the signal name to exclude the final index
526	                trimmed_signal_name = std::string(signal_name.begin(), iter);
527	            }
528	        }
529	        return std::make_pair(trimmed_signal_name, bit_index);
530	    }
531	
532	    ///@brief Retrieves a reference to the currently active .model
533	    AtomNetlist& curr_model() {
534	        if (blif_models_.empty() || ended_) {
535	            vpr_throw(VPR_ERROR_BLIF_F, filename_.c_str(), lineno_, "Expected .model");
536	        }
537	
538	        return blif_models_[blif_models_.size() - 1];
539	    }
540	
541	    void set_curr_model_blackbox(bool val) {
542	        VTR_ASSERT(blif_models_.size() == blif_models_black_box_.size());
543	        blif_models_black_box_[blif_models_black_box_.size() - 1] = val;
544	    }
545	
546	    bool verify_blackbox_model(AtomNetlist& blif_model) {
547	        LogicalModelId arch_model_id = models_.get_model_by_name(blif_model.netlist_name());
548	        const t_model& arch_model = models_.get_model(arch_model_id);
549	
550	        //Verify each port on the model
551	        //
552	        // We parse each .model as its own netlist so the IOs
553	        // get converted to blocks
554	        for (auto blk_id : blif_model.blocks()) {
555	            //Check that the port directions match
556	            if (blif_model.block_type(blk_id) == AtomBlockType::INPAD) {
557	                const auto& input_name = blif_model.block_name(blk_id);
558	
559	                //Find model port already verifies the port widths
560	                const t_model_ports* arch_model_port = find_model_port(arch_model, input_name);
561	                VTR_ASSERT(arch_model_port);
562	                VTR_ASSERT(arch_model_port->dir == IN_PORT);
563	
564	            } else {
565	                VTR_ASSERT(blif_model.block_type(blk_id) == AtomBlockType::OUTPAD);
566	
567	                const auto& raw_output_name = blif_model.block_name(blk_id);
568	
569	                std::string output_name = vtr::replace_first(raw_output_name, OUTPAD_NAME_PREFIX, "");
570	
571	                //Find model port already verifies the port widths
572	                const t_model_ports* arch_model_port = find_model_port(arch_model, output_name);
573	                VTR_ASSERT(arch_model_port);
574	
575	                VTR_ASSERT(arch_model_port->dir == OUT_PORT);
576	            }
577	        }
578	        return true;
579	    }
580	
581	    ///@brief Returns a different unique subck name each time it is called
582	    std::string unique_subckt_name() {
583	        return "unnamed_subckt" + std::to_string(unique_subckt_name_counter_++);
584	    }
585	
586	    /** @brief Sets the current block which is being processed
587	     *
588	     * Used to determine which block a .cname, .param, .attr apply to
589	     */
590	    void set_curr_block(AtomBlockId blk) {
591	        curr_block_ = blk;
592	    }
593	
594	    ///@brief Gets the current block which is being processed
595	    AtomBlockId curr_block() const {
596	        return curr_block_;
597	    }
598	
599	    /**
600	     * @brief Merges all the recorded net pairs which need to be merged
601	     *
602	     * This should only be called at the end of a .model to ensure that
603	     * all the associated driver/sink pins have been declared and connected
604	     * to their nets
605	     */
606	    void merge_conn_nets() {
607	        for (auto net_pair : curr_nets_to_merge_) {
608	            curr_model().merge_nets(net_pair.first, net_pair.second);
609	        }
610	
611	        curr_nets_to_merge_.clear();
612	    }
613	
614	  private:
615	    bool ended_ = true; //Initially no active .model
616	    std::string filename_ = "";
617	    int lineno_ = -1;
618	
619	    std::vector<AtomNetlist> blif_models_;
620	    std::vector<bool> blif_models_black_box_;
621	
622	    AtomNetlist& main_netlist_;    ///<User object we fill
623	    const std::string netlist_id_; ///<Unique identifier based on the contents of the blif file
624	    const LogicalModels& models_;
625	
626	    size_t unique_subckt_name_counter_ = 0;
627	
628	    AtomBlockId curr_block_;
629	    std::vector<std::pair<AtomNetId, AtomNetId>> curr_nets_to_merge_;
630	
631	    e_circuit_format blif_format_ = e_circuit_format::BLIF;
632	};
633	
634	vtr::LogicValue to_vtr_logic_value(blifparse::LogicValue val) {
635	    vtr::LogicValue new_val = vtr::LogicValue::UNKNOWN;
636	    switch (val) {
637	        case blifparse::LogicValue::TRUE:
638	            new_val = vtr::LogicValue::TRUE;
639	            break;
640	        case blifparse::LogicValue::FALSE:
641	            new_val = vtr::LogicValue::FALSE;
642	            break;
643	        case blifparse::LogicValue::DONT_CARE:
644	            new_val = vtr::LogicValue::DONT_CARE;
645	            break;
646	        case blifparse::LogicValue::UNKNOWN:
647	            new_val = vtr::LogicValue::UNKNOWN;
648	            break;
649	        default:
650	            VTR_ASSERT_OPT_MSG(false, "Unknown logic value");
651	    }
652	    return new_val;
653	}
654	
655	bool is_string_param(const std::string& param) {
656	    // Empty param is considered a string
657	    if (param.empty()) {
658	        return true;
659	    }
660	
661	    // There have to be at least 2 characters (the quotes)
662	    if (param.length() < 2) {
663	        return false;
664	    }
665	
666	    // The first and the last characters must be quotes
667	    size_t len = param.length();
668	    if (param[0] != '"' || param[len - 1] != '"') {
669	        return false;
670	    }
671	
672	    // There mustn't be any other quotes except for escaped ones
673	    for (size_t i = 1; i < (len - 1); ++i) {
674	        if (param[i] == '"' && param[i - 1] != '\\') {
675	            return false;
676	        }
677	    }
678	
679	    // This is a string param
680	    return true;
681	}
682	
683	bool is_binary_param(const std::string& param) {
684	    // Must be non-empty
685	    if (param.empty()) {
686	        return false;
687	    }
688	
689	    // The string must contain only '0' and '1'
690	    for (size_t i = 0; i < param.length(); ++i) {
691	        if (param[i] != '0' && param[i] != '1') {
692	            return false;
693	        }
694	    }
695	
696	    // This is a binary word param
697	    return true;
698	}
699	
700	bool is_real_param(const std::string& param) {
701	    /* Must be non-empty */
702	    if (param.empty()) {
703	        return false;
704	    }
705	
706	    // The string must match the regular expression
707	    const std::regex real_number_expr("[+-]?([0-9]*\\.[0-9]+)|([0-9]+\\.[0-9]*)");
708	    if (!std::regex_match(param, real_number_expr)) {
709	        return false;
710	    }
711	
712	    // This is a real number param
713	    return true;
714	}
715	
716	AtomNetlist read_blif(e_circuit_format circuit_format,
717	                      const char* blif_file,
718	                      const LogicalModels& models) {
719	    AtomNetlist netlist;
720	    std::string netlist_id = vtr::secure_digest_file(blif_file);
721	
722	    BlifAllocCallback alloc_callback(circuit_format, netlist, netlist_id, models);
723	    blifparse::blif_parse_filename(blif_file, alloc_callback);
724	
725	    return netlist;
726	}
