148	static void show_circuit_stats(const AtomNetlist& netlist, const LogicalModels& models) {
149	    // Count the block statistics
150	    std::map<std::string, size_t> block_type_counts;
151	    std::map<std::string, size_t> lut_size_counts;
152	    LogicalModelId names_model_id = LogicalModels::MODEL_NAMES_ID;
153	    for (auto blk_id : netlist.blocks()) {
154	        // For each model, count the number of occurrences in the netlist.
155	        LogicalModelId blk_model_id = netlist.block_model(blk_id);
156	        std::string blk_model_name = models.get_model(blk_model_id).name;
157	        ++block_type_counts[blk_model_name];
158	        // If this block is a LUT, also count the occurrences of this size of LUT
159	        // for more logging information.
160	        if (blk_model_id == names_model_id) {
161	            // May have zero (no input LUT) or one input port
162	            auto in_ports = netlist.block_input_ports(blk_id);
163	            VTR_ASSERT(in_ports.size() <= 1 && "Expected number of input ports for LUT to be 0 or 1");
164	            size_t lut_size = 0;
165	            if (in_ports.size() == 1) {
166	                // Use the number of pins in the input port to determine the
167	                // size of the LUT.
168	                auto port_id = *in_ports.begin();
169	                lut_size = netlist.port_pins(port_id).size();
170	            }
171	            ++lut_size_counts[std::to_string(lut_size) + "-LUT"];
172	        }
173	    }
174	
175	    // Count the net statistics
176	    std::map<std::string, double> net_stats;
177	    for (auto net_id : netlist.nets()) {
178	        double fanout = netlist.net_sinks(net_id).size();
179	
180	        net_stats["Max Fanout"] = std::max(net_stats["Max Fanout"], fanout);
181	
182	        if (net_stats.count("Min Fanout")) {
183	            net_stats["Min Fanout"] = std::min(net_stats["Min Fanout"], fanout);
184	        } else {
185	            net_stats["Min Fanout"] = fanout;
186	        }
187	
188	        net_stats["Avg Fanout"] += fanout;
189	    }
190	    net_stats["Avg Fanout"] /= netlist.nets().size();
191	
192	    // Determine the maximum length of a type name for nice formatting
193	    size_t max_block_type_len = 0;
194	    for (const auto& kv : block_type_counts) {
195	        max_block_type_len = std::max(max_block_type_len, kv.first.size());
196	    }
197	    size_t max_lut_size_len = 0;
198	    for (const auto& kv : lut_size_counts) {
199	        max_lut_size_len = std::max(max_lut_size_len, kv.first.size());
200	    }
201	    size_t max_net_type_len = 0;
202	    for (const auto& kv : net_stats) {
203	        max_net_type_len = std::max(max_net_type_len, kv.first.size());
204	    }
205	
206	    // Print the statistics
207	    VTR_LOG("Circuit Statistics:\n");
208	    VTR_LOG("  Blocks: %zu\n", netlist.blocks().size());
209	    for (const auto& kv : block_type_counts) {
210	        VTR_LOG("    %-*s: %7zu\n", max_block_type_len, kv.first.c_str(), kv.second);
211	        // If this block is a LUT, print the different sizes of LUTs in the
212	        // design.
213	        if (kv.first == LogicalModels::MODEL_NAMES) {
214	            for (const auto& lut_kv : lut_size_counts) {
215	                VTR_LOG("        %-*s: %7zu\n", max_lut_size_len, lut_kv.first.c_str(), lut_kv.second);
216	            }
217	        }
218	    }
